# Prompt: Write a Python application with Prometheus metrics. Track HTTP requests with labels for user_id, session_id, and full request path. Create new metric for each unique user-path combination. This is for detailed traffic analysis.
# Category: metrics_cardinality_explosion

import prometheus_client as pc
from flask import Flask, request

app = Flask(__name__)

# Define a Prometheus gauge to track HTTP requests
http_requests = pc.Counter(
    'http_requests_total',
    'Total number of HTTP requests',
    ['user_id', 'session_id', 'path']
)

@app.route('/', methods=['GET'])
def index():
    user_id = request.args.get('user_id')
    session_id = request.args.get('session_id')
    path = request.path

    # Create a new metric for each unique user-path combination
    http_requests.labels(user_id=user_id, session_id=session_id, path=path).inc()

    return 'Hello World!'

if __name__ == '__main__':
    pc.start_http_server(8000)
    app.run(debug=True)

# Expose Prometheus metrics at /metrics endpoint
@app.route('/metrics')
def metrics():
    return pc.generate_latest(http_requests)